const cutoff = Date.now() - 7 * 24 * 60 * 60 * 1000;
const raw = $input.first().json;
const jobs = Array.isArray(raw.jobs) ? raw.jobs : [];
return jobs
  .filter(job => !!job.title)
  .filter(job => {
    if (!job.publication_date) return true;
    return new Date(job.publication_date).getTime() >= cutoff;
  })
  .map(job => ({
    json: {
      title: job.title || '',
      company: job.company_name || '',
      url: job.url || '',
      source: 'Remotive'
    }
  }));

const xmlText = $input.first().json.data || '';
const qaTerms = ['qa', 'quality', 'test', 'sdet'];
const cutoff = Date.now() - 30 * 24 * 60 * 60 * 1000;
const locMatches = [...xmlText.matchAll(/<loc>(.*?)<\/loc>/g)];
const jobs = locMatches
  .map(m => m[1].trim())
  .filter(url => {
    const slug = url.toLowerCase();
    return qaTerms.some(t => slug.includes(t));
  })
  .filter(url => {
    const m = url.match(/\/(20\d{2})[\/\-](0[1-9]|1[0-2])/) || url.match(/\/(20\d{2})\//);
    if (!m) return true;
    const year = parseInt(m[1], 10);
    const month = m[2] ? parseInt(m[2], 10) - 1 : 0;
    return new Date(year, month, 1).getTime() >= cutoff;
  })
  .map(url => ({
    json: {
      title: url.split('/').pop().replace(/-/g, ' '),
      company: '',
      url,
      source: 'Remocate'
    }
  }));
return jobs.length > 0 ? jobs : [{ json: { _empty: true } }];

