const items = $input.all().filter(item => !item.json._empty);
const qaTerms = ['qa', 'quality', 'test', 'sdet', 'tester', 'automation'];

const excludeTitleTerms = [
  'us only', 'usa only', 'united states only', 'united states',
  'uk only', 'canada only', 'australia only',
  'latam only', 'latin america only', 'apac only', 'india only',
  'no sponsorship', 'us work authorization', 'authorized to work in'
];

const excludeUrlPatterns = [
  '/us/', '/usa/', '/united-states/', '/uk/', '/canada/'
];

const keepTerms = [
  'remote', 'worldwide', 'global', 'anywhere', 'international',
  'emea', 'europe', 'european', 'africa', 'kenya'
];

const seen = new Set();
const filtered = items.filter(item => {
  const title = (item.json.title || '').toLowerCase();
  const url = (item.json.url || '').toLowerCase();
  if (!title || !item.json.url) return false;
  if (seen.has(item.json.url)) return false;
  seen.add(item.json.url);

  const isQA = qaTerms.some(t => title.includes(t));
  if (!isQA) return false;

  const hasKeepSignal = keepTerms.some(t => title.includes(t));
  if (hasKeepSignal) return true;

  const isTitleExcluded = excludeTitleTerms.some(t => title.includes(t));
  if (isTitleExcluded) return false;

  const isUrlExcluded = excludeUrlPatterns.some(p => url.includes(p));
  if (isUrlExcluded) return false;

  return true;
});

if (filtered.length === 0) return [{ json: { _empty: true } }];
return filtered.map(item => ({ json: item.json }));

const jobs = $input.all();
const lines = jobs.map(j => {
  const company = j.json.company ? ` â ${j.json.company}` : '';
  const source = j.json.source ? ` [${j.json.source}]` : '';
  return `*${j.json.title}*${company}${source}\n${j.json.url}`;
});
const body = `\uD83D\uDCCB *QA Jobs Today (${jobs.length})*\n\n` + lines.join('\n\n');
return [{ json: { body } }];
